// Merge Instantly stats, active variants, experiment history, and program rules
const stats = $('Pull Instantly Campaign Stats').first().json;
const activeSheet = $('Read Active Variants').first().json;
const historySheet = $('Read Experiment History').first().json;
const programSheet = $('Read Program Doc').first().json;

// Parse active variants
const activeRows = (activeSheet.values || []).slice(1);
const champion = activeRows.find(r => r[0] === 'champion') || [];
const challenger = activeRows.find(r => r[0] === 'challenger') || [];

// Parse experiment history (last 10 rounds)
const historyRows = (historySheet.values || []).slice(1);
const recentHistory = historyRows.slice(-10).map(r => ({
  experimentId: r[0],
  date: r[1],
  championCopy: r[2],
  challengerCopy: r[3],
  championSubject: r[4],
  challengerSubject: r[5],
  championSends: parseInt(r[6]) || 0,
  challengerSends: parseInt(r[7]) || 0,
  championReplyRate: parseFloat(r[8]) || 0,
  challengerReplyRate: parseFloat(r[9]) || 0,
  winner: r[10],
  changeType: r[11] || '',
  reasoning: r[12] || ''
}));

// Parse program rules
const programRows = (programSheet.values || []).slice(1);
const programRules = programRows.map(r => `${r[0]}: ${r[1]}`).join('\n');

// Current variant data
const championData = {
  subject: champion[1] || '',
  body: champion[2] || '',
  sends: parseInt(champion[3]) || 0,
  openRate: parseFloat(champion[4]) || 0,
  replyRate: parseFloat(champion[5]) || 0
};

const challengerData = {
  subject: challenger[1] || '',
  body: challenger[2] || '',
  sends: parseInt(challenger[3]) || 0,
  openRate: parseFloat(challenger[4]) || 0,
  replyRate: parseFloat(challenger[5]) || 0
};

// Reply rate floor from env (default 1.0%)
const replyRateFloor = parseFloat($env.REPLY_RATE_FLOOR) || 1.0;

return [{
  json: {
    campaignStats: stats,
    champion: championData,
    challenger: challengerData,
    experimentHistory: recentHistory,
    totalExperiments: historyRows.length,
    programRules: programRules,
    replyRateFloor: replyRateFloor,
    bothHaveEnoughData: championData.sends >= 200 && challengerData.sends >= 200,
    hasChallenger: challengerData.body.length > 0,
    belowFloor: championData.replyRate < replyRateFloor && challengerData.replyRate < replyRateFloor && championData.sends >= 200
  }
}];

// Route based on data readiness and safety
const data = $input.first().json;

// Safety floor: if both variants are below minimum reply rate, pause
if (data.belowFloor) {
  return [{ json: { ...data, action: 'safety_pause' } }];
}

// First run with no challenger, generate one
if (!data.hasChallenger) {
  return [{ json: { ...data, action: 'generate_first_challenger' } }];
}

// Enough data to evaluate
if (data.bothHaveEnoughData) {
  return [{ json: { ...data, action: 'evaluate_and_generate' } }];
}

// Not enough data, exit
return [{ json: { ...data, action: 'wait' } }];

// Route: wait exits, safety_pause goes to Telegram, everything else goes to Claude
const data = $input.first().json;

if (data.action === 'wait') {
  return [];
}

return [$input.first()];

// Split: safety_pause goes to Telegram, everything else goes to Claude
const data = $input.first().json;

if (data.action === 'safety_pause') {
  return [{ json: { ...data, _route: 'telegram' } }];
}

return [{ json: { ...data, _route: 'claude' } }];

