// Parse Claude's JSON response
const data = $input.first().json;
const raw = data.content?.[0]?.text || '';

let parsed;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error('Failed to parse Claude response: ' + raw.substring(0, 200));
}

const previousData = $('Check Data Threshold').first().json;

return [{
  json: {
    winner: parsed.winner,
    analysis: parsed.analysis,
    hypothesis: parsed.hypothesis,
    changeType: parsed.change_type || 'unknown',
    newChallengerSubject: parsed.new_challenger_subject,
    newChallengerBody: parsed.new_challenger_body,
    confidence: parsed.confidence,
    previousChampion: previousData.champion,
    previousChallenger: previousData.challenger,
    experimentNumber: (previousData.totalExperiments || 0) + 1,
    timestamp: new Date().toISOString()
  }
}];
